UPDATE seat_locks
SET status = #{status}, updated_at = NOW()
WHERE session_id = #{sessionId}
  AND user_id = #{userId}
  AND seat_id = #{seatId}
  AND status = 0

UPDATE seat_locks
SET order_no = #{orderNo}, updated_at = NOW()
WHERE session_id = #{sessionId}
  AND user_id = #{userId}
  AND seat_id = #{seatId}
  AND status = 1

UPDATE seat_locks
SET status = 2, order_no = #{orderNo}, updated_at = NOW()
WHERE session_id = #{sessionId}
  AND user_id = #{userId}
  AND seat_id = #{seatId}
  AND status = 1
